function renderP1(){
  const cat=document.getElementById('catSel').value;
  const q=document.getElementById('tagQ').value.trim().toLowerCase();
  const main=document.getElementById('p1main');
  const info=document.getElementById('sideInfo');
  main.innerHTML='';
  if(cat){
    const pool=q?TAGS[cat].filter(t=>t.toLowerCase().includes(q)):TAGS[cat];
    info.textContent=pool.length+' 個標籤';
    const blk=document.createElement('div');blk.className='cat-blk';
    const ttl=document.createElement('div');ttl.className='cat-ttl';
    ttl.innerHTML=CATNAMES[cat]+'<span class="cat-cnt">'+pool.length+'</span>';
    const grid=document.createElement('div');grid.className='tag-grid';
    pool.forEach(t=>grid.appendChild(mkTag(t,cat)));
    blk.appendChild(ttl);blk.appendChild(grid);main.appendChild(blk);
  } else if(q){
    const pool=ALL_TAGS.filter(t=>t.toLowerCase().includes(q)||t.replace(/（[^）]*）/g,'').toLowerCase().includes(q));
    info.textContent=pool.length+' 個標籤';
    const blk=document.createElement('div');blk.className='cat-blk';
    const ttl=document.createElement('div');ttl.className='cat-ttl';
    ttl.innerHTML='搜尋結果<span class="cat-cnt">'+pool.length+'</span>';
    const grid=document.createElement('div');grid.className='tag-grid';
    pool.forEach(t=>grid.appendChild(mkTag(t,TAG_CAT[t]||'')));
    blk.appendChild(ttl);blk.appendChild(grid);main.appendChild(blk);
  } else {
    let total=0;
    Object.keys(TAGS).filter(k=>!k.startsWith('pin_')).forEach(k=>{
      total+=TAGS[k].length;
      const blk=document.createElement('div');blk.className='cat-blk';
      const ttl=document.createElement('div');ttl.className='cat-ttl';
      ttl.innerHTML=CATNAMES[k]+'<span class="cat-cnt">'+TAGS[k].length+'</span>';
      const grid=document.createElement('div');grid.className='tag-grid';
      TAGS[k].forEach(t=>grid.appendChild(mkTag(t,k)));
      blk.appendChild(ttl);blk.appendChild(grid);main.appendChild(blk);
    });
    info.textContent='共 '+total+' 個標籤';
  }
}
