  let pool=proj?AUD.filter(a=>a.project===proj):AUD;
  if(q)pool=pool.filter(a=>(a.ta||'').toLowerCase().includes(q)||(a.interest||'').toLowerCase().includes(q)||(a.project||'').toLowerCase().includes(q));
  const allTags=new Set();
  pool.forEach(a=>parseTags(a.interest).forEach(t=>allTags.add(t)));
  document.getElementById('p2stats').innerHTML='共 <strong>'+pool.length+'</strong> 組受眾 / <strong>'+allTags.size+'</strong> 個不重複興趣標籤';
  list.innerHTML='';
