    const card=document.createElement('div');card.className='aud-card';
    const ta=(a.ta||'').replace(/\r?\n/g,' ').replace(/[、，,]\s*\d+(?:訊息|名單)[^\s（(]*/g,'').replace(/\s+\d+(?:訊息|名單)\s*$/,'').trim();
    const projClean=(a.project||'').replace(/[、，,]\s*\d+(?:訊息|名單)[^\s（(]*/g,'').replace(/\s+\d+(?:訊息|名單)\s*$/,'').trim();
    const proj_badge=projClean?'<span style="font-size:11px;color:#888;background:#f5f5f6;padding:2px 6px;border-radius:10px">'+esc(projClean)+'</span>':'';
