    card.innerHTML='<div class="aud-hd"><span class="aud-ta">'+esc(ta)+'</span>'+proj_badge+type_badge+'</div><div class="aud-tgs"></div>';
    list.appendChild(card);
    const tArea=card.querySelector('.aud-tgs');
