let map_=null,marker_=null,selLoc=null;
function initMap(){
  if(map_)return;
  map_=L.map('leafletMap').setView([24.15,120.7],11);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'© OpenStreetMap'}).addTo(map_);
  map_.on('click',e=>setPin(e.latlng.lat,e.latlng.lng,'已釘選位置'));
  setTimeout(()=>map_.invalidateSize(),200);
}
function setPin(lat,lng,name){
  selLoc={lat,lng,name};
  document.getElementById('locLbl').textContent=name+' ('+lat.toFixed(4)+', '+lng.toFixed(4)+')';
  if(marker_)map_.removeLayer(marker_);
  marker_=L.marker([lat,lng]).addTo(map_).bindPopup(name).openPopup();
  map_.setView([lat,lng],14);
}
async function searchLoc(){
  const q=document.getElementById('locInput').value.trim();
  if(!q)return;
  try{
    const url='https://nominatim.openstreetmap.org/search?q='+encodeURIComponent(q+'台灣')+'&format=json&limit=1';
    const r=await fetch(url,{headers:{'Accept-Language':'zh-TW'}});
    const d=await r.json();
    if(d.length){setPin(parseFloat(d[0].lat),parseFloat(d[0].lon),d[0].display_name.split(',')[0]);}
    else document.getElementById('locLbl').textContent='找不到該地點';
  }catch(e){document.getElementById('locLbl').textContent='定位失敗';}
}

// Interest ratios
const ratioData=[
  {id:'rich',name:'Wealthy (有錢)',pct:20,checked:true},
  {id:'re',name:'Real Estate (房地產)',pct:30,checked:true},
  {id:'youth',name:'Youth (年輕人)',pct:15,checked:true},
  {id:'tech',name:'Tech (科技業)',pct:20,checked:true},
  {id:'gov',name:'Civil Service (公務員)',pct:15,checked:true}
];
function buildRatios(){
  const list=document.getElementById('ratioList');
  list.innerHTML='';
  ratioData.forEach((r,i)=>{
    const row=document.createElement('div');row.className='ratio-row';
    row.innerHTML='<input type="checkbox" class="rc" id="rc'+i+'" '+(r.checked?'checked':'')+'><span class="rn" onclick="toggleDet('+i+')">'+r.name+'</span><input type="number" class="rp" id="rp'+i+'" value="'+r.pct+'" min="0" max="100"><span class="rpct">%</span>';
    list.appendChild(row);
    const det=document.createElement('div');det.className='rdet';det.id='rdet'+i;
    TAGS[r.id].slice(0,15).forEach(t=>{
      const s=document.createElement('span');s.className='rmtag sel';s.textContent=t;
      s.onclick=()=>s.classList.toggle('sel');det.appendChild(s);
    });
    list.appendChild(det);
    row.querySelector('#rc'+i).addEventListener('change',updateRatioTotal);
    row.querySelector('#rp'+i).addEventListener('input',updateRatioTotal);
  });
  updateRatioTotal();
}
function toggleDet(i){document.getElementById('rdet'+i).classList.toggle('open');}
function updateRatioTotal(){
  let sum=0;
  ratioData.forEach((_,i)=>{if(document.getElementById('rc'+i).checked)sum+=parseInt(document.getElementById('rp'+i).value)||0;});
  const el=document.getElementById('ratioTot');
  el.textContent='合計 '+sum+'%'+(sum===100?' ✓':' (需達100%)');
  el.className='rtot '+(sum===100?'ok':'warn');
}
buildRatios();

function getRatioSummary(){
  const parts=[];
  ratioData.forEach((r,i)=>{
    if(document.getElementById('rc'+i).checked){
      const pct=parseInt(document.getElementById('rp'+i).value)||0;
      const selTags=[...document.getElementById('rdet'+i).querySelectorAll('.rmtag.sel')].map(s=>s.textContent);
      parts.push(r.name+'('+pct+'%): '+selTags.slice(0,5).join('、'));
    }
  });
  return parts.join('\n');
}

function getApiKey(){
  let k=localStorage.getItem('ant_k');
  if(!k){k=prompt('請輸入 Anthropic API Key（sk-ant-api03-…）\n（只需輸入一次，將儲存於本機）');if(k&&k.trim())localStorage.setItem('ant_k',k.trim());}
  return(k||'').trim();
}

