function randomInterests(){
  var cats=Object.keys(TAGS).filter(function(k){return k.indexOf("pin_")<0&&TAGS[k]&&TAGS[k].length>=5;});
  for(var i=cats.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=cats[i];cats[i]=cats[j];cats[j]=t;}
  var pick=cats.slice(0,20);
  var main=document.getElementById("p1main");
  main.innerHTML="";
  pick.forEach(function(cat){
    var pool=TAGS[cat].slice();
    for(var i=pool.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=pool[i];pool[i]=pool[j];pool[j]=t;}
    var sel=pool.slice(0,10);
    var blk=document.createElement("div");blk.className="cat-blk";
    var ttl=document.createElement("div");ttl.className="cat-ttl";
    ttl.innerHTML=(CATNAMES[cat]||cat)+"<span class=\cat-cnt\>"+sel.length+"</span>";
    var grid=document.createElement("div");grid.className="tag-grid";
    sel.forEach(function(t){grid.appendChild(mkTag(t,cat));});
    blk.appendChild(ttl);blk.appendChild(grid);main.appendChild(blk);
  });
  var info=document.getElementById("randomInfo");
  if(info)info.textContent="已隨機顯示 "+pick.length+" 類各 10 個標籤";
  document.getElementById("catSel").value="";
}
function cp(el){ct(el.querySelector('[data-cp]').getAttribute('data-cp'))}
function ct(text){
  const done=()=>{const t=document.getElementById('toast');t.textContent='已複製 → '+text;t.classList.add('on');clearTimeout(t._x);t._x=setTimeout(()=>t.classList.remove('on'),2000)};
  if(navigator.clipboard){navigator.clipboard.writeText(text).then(done).catch(()=>fb(text,done))}else{fb(text,done)}
}
function fb(text,cb){const a=document.createElement('textarea');a.value=text;a.style.cssText='position:fixed;opacity:0';document.body.appendChild(a);a.focus();a.select();try{document.execCommand('copy')}catch(e){}document.body.removeChild(a);cb()}
