  var html='<div class="xtag-section">';
  html+='<div class="xtag-hd"><span class="xtag-hd-title">延伸興趣（未收錄標籤）　共 '+EXTRA_TAGS.length+' 類　點擊複製<\/span>';
  html+='<button class="xtag-shuffle-all" onclick="shuffleAllXtags()">🔄 全部刷新<\/button><\/div>';
