    html+='<button class="xtag-card-shuf" id="xtag-shuf-'+gi+'" onclick="shuffleXtags('+gi+')" title="換一批">🔄<\/button><\/div>';
    html+='<div class="xtag-chips" id="xtag-chips-'+gi+'">'+_buildXtagChips(gi)+'<\/div>';
